CREATE TABLE IF NOT EXISTS ipo_history (security_code TEXT, security_name TEXT, market_type TEXT, listing_date TEXT, ld_close_change REAL, board_key TEXT, updated_at TEXT, issue_price REAL, issue_pe REAL, industry_pe REAL, fund_raised REAL, total_shares REAL, online_shares REAL, online_lottery_rate REAL, oversubscribe_multiple REAL, subscribe_upper_limit REAL, main_business TEXT, industry TEXT, circulation_mv REAL, pe_ratio REAL, ipo_date TEXT, PRIMARY KEY (security_code));
